export type AvatarFace = 'front' | 'back';
export interface AvatarPair {
  front: string;
  back: string;
}
type AvatarOverride = string | Partial<AvatarPair>;

// 兼容旧版本保存的单字符串覆盖；新版本也允许分别覆盖正面和背面。
const overrides = useLocalStorage<Record<string, AvatarOverride>>('cultivation_bar:avatars', {});

function resolvePair(name: string): AvatarPair {
  if (!name) return { front: '', back: '' };

  const defaults: AvatarPair = {
    front: DEFAULT_AVATARS[name] ?? '',
    back: DEFAULT_BACK_AVATARS[name] ?? '',
  };
  const override = overrides.value[name];
  if (typeof override === 'string') return { ...defaults, front: override };
  return {
    front: override?.front ?? defaults.front,
    back: override?.back ?? defaults.back,
  };
}

export function avatarPairOf(name: string): AvatarPair {
  return resolvePair(name);
}

export function avatarOf(name: string, face: AvatarFace = 'front'): string {
  return resolvePair(name)[face];
}

// 是否有随卡分发的默认头像。有默认头像的角色（古神/重要人物）不可自定义；
// 主角虽在默认表内但作为玩家角色始终可自定义，由调用方自行特判。
export function hasDefaultAvatar(name: string): boolean {
  return (
    !!name &&
    (Object.prototype.hasOwnProperty.call(DEFAULT_AVATARS, name) ||
      Object.prototype.hasOwnProperty.call(DEFAULT_BACK_AVATARS, name))
  );
}

export function hasAvatarPair(name: string): boolean {
  return !!name && Object.prototype.hasOwnProperty.call(DEFAULT_BACK_AVATARS, name);
}

export function useAvatar(name: Ref<string> | string | (() => string), face: AvatarFace = 'front') {
  const getter = typeof name === 'string' ? computed(() => name) : typeof name === 'function' ? computed(name) : name;
  return computed(() => resolvePair(getter.value)[face]);
}

export function setAvatar(name: string, url: string): void {
  if (!name) return;
  const current = overrides.value[name];
  const pair = typeof current === 'string' ? { front: current } : current;
  overrides.value = { ...overrides.value, [name]: { ...pair, front: url } };
}

export function setAvatarPair(name: string, pair: Partial<AvatarPair>): void {
  if (!name) return;
  const current = overrides.value[name];
  const normalized = typeof current === 'string' ? { front: current } : current;
  overrides.value = { ...overrides.value, [name]: { ...normalized, ...pair } };
}
